"use strict";(self.webpackChunklearn_data=self.webpackChunklearn_data||[]).push([[8293],{83671:(n,s)=>{s.A=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}},41709:(n,s,a)=>{a.r(s),a.d(s,{comp:()=>p,data:()=>o});var e=a(7847);const t=[(0,e.Fv)('<h2 id="事务" tabindex="-1"><a class="header-anchor" href="#事务"><span>事务</span></a></h2><p>事务是一组操作的集合，事务会把所有操作作为一个整体一起向系统提交或撤销操作请求，即这些操作要么同时成功，要么同时失败</p><p>当我们要进行的操作非常多时，比如要依次删除很多个表的数据，我们就需要执行大量的SQL语句来完成，这些数据库操作语句就可以构成一个事务！</p><p>只有Innodb引擎支持事务</p><h3 id="使用" tabindex="-1"><a class="header-anchor" href="#使用"><span>使用</span></a></h3><p>Mysql 默认开启事务自动提交</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 查看事务提交方式（1=自动提交，0=手动提交）</span>\n<span class="token keyword">SELECT</span> @<span class="token variable">@autocommit</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 设置为手动提交</span>\n<span class="token keyword">SET</span> @<span class="token variable">@autocommit</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 设置为自动提交</span>\n<span class="token keyword">SET</span> @<span class="token variable">@autocommit</span> <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="手动控制事务" tabindex="-1"><a class="header-anchor" href="#手动控制事务"><span>手动控制事务</span></a></h4><h5 id="方式一" tabindex="-1"><a class="header-anchor" href="#方式一"><span>方式一</span></a></h5><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 开启事务</span>\n<span class="token keyword">BEGIN</span><span class="token punctuation">;</span>  <span class="token comment">-- 或 START TRANSACTION;</span>\n\n<span class="token comment">-- 执行SQL操作</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> money <span class="token operator">-</span> <span class="token number">1000</span> <span class="token keyword">WHERE</span> name <span class="token operator">=</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">;</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> money <span class="token operator">+</span> <span class="token number">1000</span> <span class="token keyword">WHERE</span> name <span class="token operator">=</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 提交事务</span>\n<span class="token keyword">COMMIT</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 或者回滚事务（撤销所有操作）</span>\n<span class="token keyword">ROLLBACK</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="方式二" tabindex="-1"><a class="header-anchor" href="#方式二"><span>方式二</span></a></h5><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 关闭自动提交</span>\n<span class="token keyword">SET</span> @<span class="token variable">@autocommit</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 执行SQL</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> money <span class="token operator">-</span> <span class="token number">1000</span> <span class="token keyword">WHERE</span> name <span class="token operator">=</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">;</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> money <span class="token operator">+</span> <span class="token number">1000</span> <span class="token keyword">WHERE</span> name <span class="token operator">=</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 提交事务</span>\n<span class="token keyword">COMMIT</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 或回滚</span>\n<span class="token keyword">ROLLBACK</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="事务四大特性-acid" tabindex="-1"><a class="header-anchor" href="#事务四大特性-acid"><span>事务四大特性 (ACID)</span></a></h3><table><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td>原子性 Atomicity</td><td>事务是不可分割的最小操作单元，要么全部成功，要么全部失败</td></tr><tr><td>一致性 Consistency</td><td>事务完成时，必须使所有数据保持一致状态</td></tr><tr><td>隔离性 Isolation</td><td>数据库提供的隔离机制，保证事务不受外部并发操作影响的独立环境下运行</td></tr><tr><td>持久性 Durability</td><td>事务一旦提交或回滚，它对数据库中数据的改变就是永久的</td></tr></tbody></table><h4 id="原子性" tabindex="-1"><a class="header-anchor" href="#原子性"><span>原子性</span></a></h4><p>一个事务（transaction）中的所有操作，要么全部完成，要么全部不完成，不会结束在中间某个环节。</p><p>事务在执行过程中发生错误，会被回滚（Rollback）到事务开始前的状态，就像这个事务从来没有执行过一样。</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 要么两条都执行成功，要么都不执行</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> money <span class="token operator">-</span> <span class="token number">1000</span> <span class="token keyword">WHERE</span> name <span class="token operator">=</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">;</span>  <span class="token comment">-- ✓</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> money <span class="token operator">+</span> <span class="token number">1000</span> <span class="token keyword">WHERE</span> name <span class="token operator">=</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">;</span>  <span class="token comment">-- ✗</span>\n<span class="token comment">-- 如果第二条失败，第一条也会回滚</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="一致性" tabindex="-1"><a class="header-anchor" href="#一致性"><span>一致性</span></a></h4><p>在事务开始之前和事务结束以后，数据库的完整性没有被破坏。</p><p>这表示写入的资料必须完全符合所有的预设规则，这包含资料的精确度、串联性以及后续数据库可以自发性地完成预定的工作。</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 转账前后，总金额保持不变</span>\n<span class="token comment">-- 转账前：张三1000 + 李四1000 = 2000</span>\n<span class="token comment">-- 转账后：张三0 + 李四2000 = 2000</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="隔离性" tabindex="-1"><a class="header-anchor" href="#隔离性"><span>隔离性</span></a></h4><p>数据库允许多个并发事务同时对其数据进行读写和修改的能力，隔离性可以防止多个事务并发执行时由于交叉执行而导致数据的不一致。</p><p>事务隔离分为不同级别，包括:</p><ul><li>读未提交（Read uncommitted）</li><li>读提交（read committed）</li><li>可重复读（repeatable read）</li><li>串行化（Serializable）。</li></ul><h4 id="持久性" tabindex="-1"><a class="header-anchor" href="#持久性"><span>持久性</span></a></h4><p>事务处理结束后，对数据的修改就是永久的，即便系统故障也不会丢失</p><h3 id="并发事务问题" tabindex="-1"><a class="header-anchor" href="#并发事务问题"><span>并发事务问题</span></a></h3><table><thead><tr><th>问题</th><th>说明</th></tr></thead><tbody><tr><td>脏读（Dirty Read）</td><td>一个事务读到另一个事务还没提交的数据</td></tr><tr><td>不可重复读（Non-Repeatable Read）</td><td>一个事务先后读取同一条记录，但两次读取的数据不同</td></tr><tr><td>幻读（Phantom Read）</td><td>一个事务查询数据时，没有对应记录，但插入数据时又发现数据已存在</td></tr></tbody></table><h4 id="示例" tabindex="-1"><a class="header-anchor" href="#示例"><span>示例</span></a></h4><h5 id="脏读" tabindex="-1"><a class="header-anchor" href="#脏读"><span>脏读</span></a></h5><p>读到存在一下就被删除的数据</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 事务A</span>\n<span class="token keyword">BEGIN</span><span class="token punctuation">;</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> <span class="token number">2000</span> <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>\n<span class="token comment">-- 未提交</span>\n\n<span class="token comment">-- 事务B</span>\n<span class="token keyword">SELECT</span> money <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 读到2000（脏数据）</span>\n\n<span class="token comment">-- 事务A回滚</span>\n<span class="token keyword">ROLLBACK</span><span class="token punctuation">;</span>  <span class="token comment">-- 事务B读到的数据无效</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="不可重复读" tabindex="-1"><a class="header-anchor" href="#不可重复读"><span>不可重复读</span></a></h5><p>两次获取的数据不一致</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 事务A</span>\n<span class="token keyword">BEGIN</span><span class="token punctuation">;</span>\n<span class="token keyword">SELECT</span> money <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 读到1000</span>\n\n<span class="token comment">-- 事务B</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> <span class="token number">2000</span> <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>\n<span class="token keyword">COMMIT</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 事务A</span>\n<span class="token keyword">SELECT</span> money <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 读到2000（前后不一致）</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="幻读" tabindex="-1"><a class="header-anchor" href="#幻读"><span>幻读</span></a></h5><p>查询数据时，没有对应记录，但插入数据时又发现数据已存在</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 事务A</span>\n<span class="token keyword">BEGIN</span><span class="token punctuation">;</span>\n<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span>  <span class="token comment">-- 查询不到</span>\n\n<span class="token comment">-- 事务B</span>\n<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> account <span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token string">&#39;test&#39;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">COMMIT</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 事务A</span>\n<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> account <span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token string">&#39;test&#39;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 插入失败，主键冲突（明明查不到）</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="事务隔离级别" tabindex="-1"><a class="header-anchor" href="#事务隔离级别"><span>事务隔离级别</span></a></h3><table><thead><tr><th>隔离级别</th><th>脏读</th><th>不可重复读</th><th>幻读</th><th>性能</th></tr></thead><tbody><tr><td>Read Uncommitted（读未提交）</td><td>✓</td><td>✓</td><td>✓</td><td>最高</td></tr><tr><td>Read Committed（读已提交）</td><td>✗</td><td>✓</td><td>✓</td><td>较高</td></tr><tr><td>Repeatable Read（可重复读，默认）</td><td>✗</td><td>✗</td><td>✓</td><td>较低</td></tr><tr><td>Serializable（串行化）</td><td>✗</td><td>✗</td><td>✗</td><td>最低</td></tr></tbody></table><h4 id="读未提交" tabindex="-1"><a class="header-anchor" href="#读未提交"><span>读未提交</span></a></h4><ul><li>事务可以读取其他事务未提交的数据</li><li>性能最高，但数据一致性最差</li><li>几乎不使用</li><li>脏读 不可重复读 幻读均会发生</li></ul><h4 id="读已提交" tabindex="-1"><a class="header-anchor" href="#读已提交"><span>读已提交</span></a></h4><ul><li>只能读取已提交的数据，解决了脏读</li><li>Oracle、SQL Server 的默认隔离级别</li><li>仍然存在不可重复读和幻读</li></ul><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 会话A</span>\n<span class="token keyword">SET</span> <span class="token keyword">SESSION</span> <span class="token keyword">TRANSACTION</span> <span class="token keyword">ISOLATION</span> <span class="token keyword">LEVEL</span> <span class="token keyword">READ</span> <span class="token keyword">COMMITTED</span><span class="token punctuation">;</span>\n<span class="token keyword">BEGIN</span><span class="token punctuation">;</span>\n<span class="token keyword">SELECT</span> money <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 读到1000</span>\n\n<span class="token comment">-- 会话B（在会话A之后执行）</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> <span class="token number">2000</span> <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>\n<span class="token keyword">COMMIT</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 会话A</span>\n<span class="token keyword">SELECT</span> money <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 读到2000（不可重复读）</span>\n<span class="token comment">-- INSERT 就幻读</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="可重复读" tabindex="-1"><a class="header-anchor" href="#可重复读"><span>可重复读</span></a></h4><p>MVCC 机制解决幻读</p><ul><li>MySQL 的默认隔离级别</li><li>同一事务中多次读取同一数据，结果一致，解决了不可重复读</li><li>MySQL 通过 MVCC 机制基本解决了幻读（但某些场景仍可能发生）</li></ul><h4 id="串行化" tabindex="-1"><a class="header-anchor" href="#串行化"><span>串行化</span></a></h4><ul><li>最高隔离级别，完全串行执行</li><li>解决所有并发问题，但性能最差</li><li>通过锁机制，强制事务串行执行</li></ul><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 会话A</span>\n<span class="token keyword">SET</span> <span class="token keyword">SESSION</span> <span class="token keyword">TRANSACTION</span> <span class="token keyword">ISOLATION</span> <span class="token keyword">LEVEL</span> <span class="token keyword">SERIALIZABLE</span><span class="token punctuation">;</span>\n<span class="token keyword">BEGIN</span><span class="token punctuation">;</span>\n<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> account <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>\n\n<span class="token comment">-- 会话B</span>\n<span class="token keyword">UPDATE</span> account <span class="token keyword">SET</span> money <span class="token operator">=</span> <span class="token number">2000</span> <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 会被阻塞，等待会话A提交</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="场景" tabindex="-1"><a class="header-anchor" href="#场景"><span>场景</span></a></h4><table><thead><tr><th>隔离级别</th><th>适用场景</th></tr></thead><tbody><tr><td>Read Uncommitted</td><td>几乎不用，数据一致性太差</td></tr><tr><td>Read Committed</td><td>Oracle、SQL Server 默认，适合大多数场景</td></tr><tr><td>Repeatable Read</td><td>MySQL 默认，兼顾性能和一致性</td></tr><tr><td>Serializable</td><td>极高一致性要求，如金融核心系统</td></tr></tbody></table>',55)],l={},p=(0,a(83671).A)(l,[["render",function(n,s){return(0,e.uX)(),(0,e.CE)("div",null,t)}]]),o=JSON.parse('{"path":"/code/%E4%B8%AD%E9%97%B4%E4%BB%B6/Mysql/5.html","title":"Mysql - 5 事务","lang":"zh-CN","frontmatter":{"title":"Mysql - 5 事务","category":["code"],"tag":["中间件","Mysql"],"order":-0.6,"description":"事务 事务是一组操作的集合，事务会把所有操作作为一个整体一起向系统提交或撤销操作请求，即这些操作要么同时成功，要么同时失败 当我们要进行的操作非常多时，比如要依次删除很多个表的数据，我们就需要执行大量的SQL语句来完成，这些数据库操作语句就可以构成一个事务！ 只有Innodb引擎支持事务 使用 Mysql 默认开启事务自动提交 手动控制事务 方式一 方...","head":[["meta",{"property":"og:url","content":"http://ekkosonya.cn/code/%E4%B8%AD%E9%97%B4%E4%BB%B6/Mysql/5.html"}],["meta",{"property":"og:site_name","content":"EkkoSonya\'s Blog"}],["meta",{"property":"og:title","content":"Mysql - 5 事务"}],["meta",{"property":"og:description","content":"事务 事务是一组操作的集合，事务会把所有操作作为一个整体一起向系统提交或撤销操作请求，即这些操作要么同时成功，要么同时失败 当我们要进行的操作非常多时，比如要依次删除很多个表的数据，我们就需要执行大量的SQL语句来完成，这些数据库操作语句就可以构成一个事务！ 只有Innodb引擎支持事务 使用 Mysql 默认开启事务自动提交 手动控制事务 方式一 方..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-03-04T16:30:07.000Z"}],["meta",{"property":"article:author","content":"EkkoSonya"}],["meta",{"property":"article:tag","content":"中间件"}],["meta",{"property":"article:tag","content":"Mysql"}],["meta",{"property":"article:modified_time","content":"2026-03-04T16:30:07.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Mysql - 5 事务\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-03-04T16:30:07.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"EkkoSonya\\",\\"url\\":\\"http://ekkosonya.cn\\"}]}"]]},"headers":[{"level":2,"title":"事务","slug":"事务","link":"#事务","children":[{"level":3,"title":"使用","slug":"使用","link":"#使用","children":[{"level":4,"title":"手动控制事务","slug":"手动控制事务","link":"#手动控制事务","children":[{"level":5,"title":"方式一","slug":"方式一","link":"#方式一","children":[]},{"level":5,"title":"方式二","slug":"方式二","link":"#方式二","children":[]}]}]},{"level":3,"title":"事务四大特性 (ACID)","slug":"事务四大特性-acid","link":"#事务四大特性-acid","children":[{"level":4,"title":"原子性","slug":"原子性","link":"#原子性","children":[]},{"level":4,"title":"一致性","slug":"一致性","link":"#一致性","children":[]},{"level":4,"title":"隔离性","slug":"隔离性","link":"#隔离性","children":[]},{"level":4,"title":"持久性","slug":"持久性","link":"#持久性","children":[]}]},{"level":3,"title":"并发事务问题","slug":"并发事务问题","link":"#并发事务问题","children":[{"level":4,"title":"示例","slug":"示例","link":"#示例","children":[{"level":5,"title":"脏读","slug":"脏读","link":"#脏读","children":[]},{"level":5,"title":"不可重复读","slug":"不可重复读","link":"#不可重复读","children":[]},{"level":5,"title":"幻读","slug":"幻读","link":"#幻读","children":[]}]}]},{"level":3,"title":"事务隔离级别","slug":"事务隔离级别","link":"#事务隔离级别","children":[{"level":4,"title":"读未提交","slug":"读未提交","link":"#读未提交","children":[]},{"level":4,"title":"读已提交","slug":"读已提交","link":"#读已提交","children":[]},{"level":4,"title":"可重复读","slug":"可重复读","link":"#可重复读","children":[]},{"level":4,"title":"串行化","slug":"串行化","link":"#串行化","children":[]},{"level":4,"title":"场景","slug":"场景","link":"#场景","children":[]}]}]}],"git":{"createdTime":1772641807000,"updatedTime":1772641807000,"contributors":[{"name":"EkkoSonya","email":"ekkosonya@163.com","commits":1}]},"readingTime":{"minutes":5.08,"words":1523},"filePathRelative":"code/中间件/Mysql/5.md","localizedDate":"2026年3月4日","excerpt":"<h2>事务</h2>\\n<p>事务是一组操作的集合，事务会把所有操作作为一个整体一起向系统提交或撤销操作请求，即这些操作要么同时成功，要么同时失败</p>\\n<p>当我们要进行的操作非常多时，比如要依次删除很多个表的数据，我们就需要执行大量的SQL语句来完成，这些数据库操作语句就可以构成一个事务！</p>\\n<p>只有Innodb引擎支持事务</p>\\n<h3>使用</h3>\\n<p>Mysql 默认开启事务自动提交</p>\\n<div class=\\"language-sql\\" data-ext=\\"sql\\" data-title=\\"sql\\"><pre class=\\"language-sql\\"><code><span class=\\"token comment\\">-- 查看事务提交方式（1=自动提交，0=手动提交）</span>\\n<span class=\\"token keyword\\">SELECT</span> @<span class=\\"token variable\\">@autocommit</span><span class=\\"token punctuation\\">;</span>\\n\\n<span class=\\"token comment\\">-- 设置为手动提交</span>\\n<span class=\\"token keyword\\">SET</span> @<span class=\\"token variable\\">@autocommit</span> <span class=\\"token operator\\">=</span> <span class=\\"token number\\">0</span><span class=\\"token punctuation\\">;</span>\\n\\n<span class=\\"token comment\\">-- 设置为自动提交</span>\\n<span class=\\"token keyword\\">SET</span> @<span class=\\"token variable\\">@autocommit</span> <span class=\\"token operator\\">=</span> <span class=\\"token number\\">1</span><span class=\\"token punctuation\\">;</span>\\n</code></pre></div>","autoDesc":true}')}}]);